let roadmapData = { roadmap: '', tech_stack: '', features: '' };
try {
  const rawText = $node["CEO Agent (LLM)"].json.choices[0].message.content;
  roadmapData = JSON.parse(rawText);
} catch (e) {
  roadmapData.roadmap = "Develop simple HTML application.";
  roadmapData.tech_stack = "HTML5, CSS3, Vanilla JS";
  roadmapData.features = $node["Set Initial State"].json.software_idea;
}
return {
  ...$json,
  ceo_roadmap: roadmapData.roadmap,
  ceo_tech_stack: roadmapData.tech_stack,
  ceo_features: roadmapData.features
};

let prdData = { prd_markdown: '' };
try {
  const rawText = $node["PM Agent (LLM)"].json.choices[0].message.content;
  prdData = JSON.parse(rawText);
} catch (e) {
  prdData.prd_markdown = `# PRD\n\n## Requirements\n- Build app with tech: ${$json.ceo_tech_stack}\n- Features: ${$json.ceo_features}`;
}
return {
  ...$json,
  prd_markdown: prdData.prd_markdown
};

let devData = { code: '', filename: 'index.html' };
try {
  const rawText = $node["Developer Agent (LLM)"].json.choices[0].message.content;
  devData = JSON.parse(rawText);
} catch (e) {
  devData.code = "<!DOCTYPE html><html><body><h1>Error generating code</h1></body></html>";
}
return {
  ...$json,
  dev_code: devData.code,
  dev_filename: devData.filename
};

let qaData = { qa_report: '', status: 'PASS', corrected_code: '' };
try {
  const rawText = $node["QA Agent (LLM)"].json.choices[0].message.content;
  qaData = JSON.parse(rawText);
} catch (e) {
  qaData.qa_report = "Failed to parse QA report.";
  qaData.status = "PASS";
  qaData.corrected_code = $json.dev_code;
}
return {
  ...$json,
  qa_report: qaData.qa_report,
  qa_status: qaData.status,
  qa_corrected_code: qaData.corrected_code
};

