let fixData = { code: '' };
try {
  const rawText = $node["Developer Fix (LLM)"].json.choices[0].message.content;
  fixData = JSON.parse(rawText);
} catch (e) {
  fixData.code = $node["Parse QA Output"].json.qa_corrected_code;
}
return {
  ...$json,
  final_code: fixData.code,
  final_source: 'Developer Fixed'
};

let finalCode = '';
let source = '';

try {
  // If we came from the QA Passed route
  if ($node["QA Passed?"].json.qa_corrected_code) {
    finalCode = $node["QA Passed?"].json.qa_corrected_code;
    source = 'Direct Pass';
  } else {
    // If we came from the Dev Fix route
    finalCode = $node["Parse Dev Fix"].json.final_code;
    source = 'Developer Fix';
  }
} catch (e) {
  // Fallback
  finalCode = $node["Parse QA Output"].json.qa_corrected_code || $node["Parse Developer Output"].json.dev_code;
  source = 'Fallback';
}

const filename = $node["Parse Developer Output"].json.dev_filename || 'index.html';
const binaryData = Buffer.from(finalCode, 'utf-8').toString('base64');

return {
  json: {
    filename: filename,
    code_length: finalCode.length,
    source: source
  },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'text/html',
      fileName: filename
    }
  }
};
